    /** Parse a `key=value,…` shorthand back into a PveQemuScsiConfig. */
    public static function fromShorthand(?string $raw): ?self
    {
        if ($raw === null) return null;
        $data = [];
        $defaultKeyConsumed = false;
        foreach (explode(',', $raw) as $part) {
            if ($part === '') continue;
            $eq = strpos($part, '=');
            if ($eq === false) {
                
                if (!$defaultKeyConsumed) {
                    $data['file'] = $part;
                    $defaultKeyConsumed = true;
                    continue;
                }
                
                continue;
            }
            $k = substr($part, 0, $eq);
            $v = substr($part, $eq + 1);
            $data[$k] = $v;
        }
        return new self($data);
    }
